const item = $input.item;
const binary = item.binary?.data;
if (!binary?.data) {
  throw new Error('Expected binary.data from Read this text file from disk');
}

const content = Buffer.from(binary.data, 'base64').toString('utf8');
return [{
  json: {
    filename: binary.fileName || 'input.txt',
    content
  }
}];

const item = $input.item.json;
const content = item.content || '';
const filename = item.filename || 'input.txt';

const maxChunkLength = 1200;
const normalized = content.replace(/
/g, '
').trim();
if (!normalized) {
  throw new Error('Input content is empty');
}

const paragraphs = normalized.split(/
\s*
/);
const chunks = [];
let current = '';

for (const paragraph of paragraphs) {
  const candidate = current ? `${current}

${paragraph}` : paragraph;
  if (candidate.length <= maxChunkLength) {
    current = candidate;
  } else {
    if (current) chunks.push(current);
    if (paragraph.length <= maxChunkLength) {
      current = paragraph;
    } else {
      for (let i = 0; i < paragraph.length; i += maxChunkLength) {
        chunks.push(paragraph.slice(i, i + maxChunkLength));
      }
      current = '';
    }
  }
}
if (current) chunks.push(current);

return chunks.map((chunk, index) => ({
  json: {
    filename,
    content: chunk.trim(),
    chunk_index: index + 1,
    total_chunks: chunks.length
  }
}));

const item = $input.item.json;
const filename = item.filename;
const titlePrefix = filename.replace(/\.txt$/i, '');
const chunkIndex = item.chunk_index;
const totalChunks = item.total_chunks;
const ingestedAt = new Date().toISOString();

return [{
  json: {
    source: 'file_ingest',
    category: 'project_note',
    title: `${titlePrefix} :: chunk ${String(chunkIndex).padStart(2, '0')}` ,
    content: item.content,
    tags: ['openbrain','file_ingest'],
    filename,
    chunk_index: chunkIndex,
    total_chunks: totalChunks,
    ingested_at: ingestedAt,
    metadata_json: {
      filename,
      chunk_index: chunkIndex,
      total_chunks: totalChunks,
      ingested_at: ingestedAt
    }
  }
}];
